const XLSX = require\('xlsx'\);
const wb = XLSX.readFile\('حسابات البنوك \(1\).xlsx'\);

console.log\('=== ALL SHEET NAMES ==='\);
console.log\(wb.SheetNames\);

// Read main page with full cell info
const mainSheet = wb.Sheets['الصفحه الرئسية'];
console.log\('\\n=== MAIN PAGE \(الصفحه الرئسية\) - All cells ==='\);
const range = XLSX.utils.decode_range\(mainSheet['!ref']\);
console.log\('Range:', mainSheet['!ref']\);

// Print row by row
for \(let r = range.s.r; r <= Math.min\(range.e.r, 50\); r++\) {
  let row = [];
  for \(let c = range.s.c; c <= range.e.c; c++\) {
    const cell = mainSheet[XLSX.utils.encode_cell\({r, c}\)];
    row.push\(cell ? cell.v : ''\);
  }
  // Only print non-empty rows
  if \(row.some\(v => v !== ''\)\) {
    console.log\('Row ' + r + ': ' + JSON.stringify\(row\)\);
  }
}

// Check merges
if \(mainSheet['!merges']\) {
  console.log\('\\n=== MERGED CELLS ==='\);
  mainSheet['!merges'].forEach\(m => {
    console.log\(XLSX.utils.encode_range\(m\)\);
  }\);
}
")

