const XLSX = require\('xlsx'\);
const wb = XLSX.readFile\('حسابات البنوك \(1\).xlsx'\);

// Check which sheet number maps to which bank
for \(let i = 1; i <= 22; i++\) {
  const s = wb.Sheets[String\(i\)];
  if \(!s\) continue;
  const range = XLSX.utils.decode_range\(s['!ref']\);
  // Find bank name in first few rows
  for \(let r = range.s.r; r <= Math.min\(range.s.r + 5, range.e.r\); r++\) {
    for \(let c = range.s.c; c <= range.e.c; c++\) {
      const cell = s[XLSX.utils.encode_cell\({r, c}\)];
      if \(cell && typeof cell.v === 'string' && cell.v.includes\('بنك'\)\) {
        console.log\('Sheet ' + i + ' => ' + cell.v + ' \(rows: ' + \(range.e.r - range.s.r\) + '\)'\);
        break;
      }
    }
  }
}
")

